import React from "react";
import styles from "./ProductPopup.module.css";
import Image from "next/image";

export interface ProductPopupProps {
  product: {
    id: string;
    title: string;
    description: string;
    image: string;
    price: number;
    stock: number;
    color?: string;
  };
  onClose: () => void;
  onAddToCart: () => void;
}

const ProductPopup: React.FC<ProductPopupProps> = ({ product, onClose, onAddToCart }) => {
  return (
    <div className={styles.overlay} onClick={onClose}>
      <div className={styles.popup} onClick={e => e.stopPropagation()}>
        <button className={styles.closeBtn} onClick={onClose}>×</button>
        <div className={styles.imageWrap}>
          <Image src={product.image} alt={product.title} width={220} height={180} />
        </div>
        <div className={styles.infoWrap}>
          <h2 className={styles.title}>{product.title}</h2>
          <div className={styles.desc}>{product.description}</div>
          <div className={styles.stock}>У наявності: <b>{product.stock} шт</b></div>
          <div className={styles.color}>Колір: {product.color || "білий"}</div>
          <div className={styles.bottomRow}>
            <button className={styles.addBtn} onClick={onAddToCart}>+</button>
            <span className={styles.price}>{product.price}$</span>
          </div>
        </div>
      </div>
    </div>
  );
};

export default ProductPopup;
